var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……크르르르윽!","JPN":"……グルルル！","ENG":"...Grrrrgh!","TWN":"……咕呃呃呃呃！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE"},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 끝입니다. 하베스터.","JPN":"これで終わりです、ハーベスター。","ENG":"This ends here, Harvester.","TWN":"就此結束吧，收割者。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"커억……!","JPN":"ガハッ……！","ENG":"Graah...!","TWN":"呃……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어때요, 분한가요?","JPN":"どうですか？　悔しいでしょう？","ENG":"How do you feel? Angry?","TWN":"怎麼樣，氣憤嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 날뛰어 봤자, 당신은 아직 저와 같은 무대에 설 수 없어요.","JPN":"どれだけ足掻こうと、あなたはまだ私と同じ舞台には立てません。","ENG":"No matter how hard you try, you will never stand on the same stage as me.","TWN":"無論怎麼掙扎，你還無法站在和我同樣的舞台上。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 기억하도록 하세요.","JPN":"だから覚えておきなさい。","ENG":"So let this moment sink in.","TWN":"所以請記住吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 감정을, 치욕을, 종으로서 열등함을……. 밑 바닥 없는 절망의 끝을.","JPN":"その感情を、屈辱を、種の劣等感を……底知れない絶望の果てを。","ENG":"Your emotion, your shame, and your inferiority as a species... The end of a bottomless despair.","TWN":"那種情緒，那種恥辱，作為一個物種的劣等感……無盡的絕望的盡頭。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……크윽.","JPN":"……くうっ。","ENG":"...Kgh.","TWN":"……科科。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크하아아아아악──!!","JPN":"クアアアアアアアーー！！","ENG":"KRAAAAAAGH!!","TWN":"嘎啊啊啊啊啊──！！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"또 죽음으로 다른 개체에게 정보를 넘길 셈이로군요.","JPN":"また、死ぬことによって別の個体に情報を渡そうとしてますね。","ENG":"Again, passing information to another of your kind upon death.","TWN":"又一次，想透過死亡將資訊傳遞給其他個體嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 죽지 않는다면, 무가치한 일이겠죠.","JPN":"でも死ねないなら意味のないこと。","ENG":"But if you don't die, it will be a worthless attempt.","TWN":"但如果死不了，那就毫無意義了吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……여긴. 어디?","JPN":"……ココハ、ドコダ？","ENG":"...Where. Is this?","TWN":"……這是。哪？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그곳은 제 거울 속. <color=#ffd34c>파노라마</color>의 세계.","JPN":"そこは私の鏡の中。<color=#ffd34c>パノラマ</color>の世界。","ENG":"This is within my mirror. The world of <color=#ffd34c>Panorama</color>.","TWN":"你在我的鏡子裡。<color=#ffd34c>全景</color>的世界裡。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마왕</color>과 계약하여 얻은, 잊혀진 세계의 편린이죠.","JPN":"<color=#ffd34c>魔王</color>との契約で手に入れた、忘れられた世界の片鱗です。","ENG":"It's a piece of the forgotten world that I obtained through a contract with <color=#ffd34c>the Demon Lord</color>.","TWN":"這是與<color=#ffd34c>魔王</color>簽訂契約後獲得的，遺忘世界的碎片。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……이곳.","JPN":"……ココ。","ENG":"...This place.","TWN":"……這裡。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"알고 있다. 멸망한.","JPN":"知ッテイル。滅ビタ。","ENG":"I know. Destroyed.","TWN":"滅亡的。味道。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르르르……!","JPN":"グルルル……！","ENG":"Grrr...!","TWN":"嗚喔喔喔……！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……저건?","JPN":"……アレハ？","ENG":"...That's?","TWN":"……那是？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"동족?","JPN":"同族？","ENG":"My kind?","TWN":"我的同類？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 그건 당신에게서 비춰진 거울상.","JPN":"そうです。あれは鏡に映ったあなた。","ENG":"Yes. That is a reflection of you.","TWN":"是的，那是從你身上反射出來的鏡像。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시간과 공간마저 단절된 그곳에서 당신은 완전히 똑같은 자신과 충돌하게 될 겁니다.","JPN":"時間と空間すら断絶されたその場所で、あなたはもう一人の自分とぶつかることになるでしょう。","ENG":"With time and space cut off from the world, you will face an exact version of yourself.","TWN":"在這個時間和空間都被切斷的地方，你將會與完全相同的自己相遇。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 걸 포기하고, 저에게 완벽히 굴복하게 될 때까지.","JPN":"すべてを諦め、私に屈服するまで。","ENG":"Until you give up everything and completely submit to me.","TWN":"放棄一切吧，直到你完全屈服於我。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크하아아악! 죽어!","JPN":"クアアアア！　死ネ！","ENG":"Graaa! Die!","TWN":"啊啊啊啊啊！死！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"죽여버리겠다!","JPN":"殺シテヤル！","ENG":"I KILL YOU!","TWN":"殺了！你！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 설 무대는 제가 곧 준비해 놓도록 하죠.","JPN":"そのうち、あなたが立つ舞台を用意しておきます。","ENG":"I will prepare a stage for you soon.","TWN":"我會馬上為你準備好登場的舞台。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 제가 부를 때까지 그곳에서 리허설을 준비하길 바랍니다.","JPN":"だから私が呼びに来るまで、そこでリハーサルを続けていてください。","ENG":"Until I call for you, rehearse your role in here.","TWN":"所以請在那邊準備彩排，直到我叫你為止。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"영원히…….","JPN":"永遠に……","ENG":"Forever...","TWN":"永遠……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……무슨 일이죠, 매니저?","JPN":"……マネージャー、どうかしましたか？","ENG":"...Manager, what is it?","TWN":"……有什麼事嗎，經紀人？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완님, 지금 어디세요?","JPN":"スワンさん、今どこですか？","ENG":"Miss Swan, where are you right now?","TWN":"史旺，你現在在哪？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"촬영 때문에 다들 기다리고 계신단 말이에요! 말도 없이 갑자기 사라져 버리면 어떡해요?","JPN":"皆さん撮影のために待っているんです！　何も言わずに消えたら困ります！","ENG":"Everyone's waiting on you for the shoot! How could you suddenly leave without saying a word?","TWN":"大家都在等著拍攝呢！你怎麼不打招呼就突然消失了？！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언성을 높이지 마세요.","JPN":"大声は控えてください。","ENG":"Please don't raise your voice.","TWN":"別那麼大聲。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본을 수정하고 있었답니다. 새 배역에 걸맞은 배우를 찾았거든요.","JPN":"脚本を修正していたんです。新しい役にぴったりな俳優を見つけたので。","ENG":"I was revising the script because I found someone perfect for the new role.","TWN":"我修改了劇本，因為找到了適合新角色的演員。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 좀 더 수월하게 이야기를 풀어나갈 수 있겠죠.","JPN":"これでもっとスムーズに物語を進められるでしょう。","ENG":"I believe this will allow us to tell the story more easily.","TWN":"這樣一來，就能更順利地講好故事了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"네? 그게 무슨 말씀이세요!?","JPN":"え？　どういうことですか？","ENG":"What? What do you mean?!","TWN":"啊？什麼意思！？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"캐스팅은 이미 확정됐잖아요! 여기서 또 배역을 바꾸시겠다고요?","JPN":"キャスティングはもう確定したじゃないですか！　ここでまた役を交代するということですか？","ENG":"Casting has already been fixed! But you want to change roles again?","TWN":"演員已經定好了！你確定要換角色嗎？！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"감독님께서도 화가 많이 나셨다고요!","JPN":"監督もすごく怒ってますよ！","ENG":"The director is also fuming!","TWN":"導演現在也非常生氣！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언성을 높이지 말라고 했을 텐데요?","JPN":"大声を控えてください、と言ったはずですよ。","ENG":"Didn't I tell you to not raise your voice?","TWN":"我說了，別那麼大聲吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 보잘것없는 재능에도, 당신이 업계에 남아 있을 수 있도록 손을 써준 사람이 누구죠?","JPN":"その取るに足らない才能でもこの業界にいられるように手を回してあげたのは、誰だと思っているんですか？","ENG":"Who was the one who helped you stay in this industry despite your meager talents, hmm?","TWN":"憑你那微不足道的才能，是誰才讓你繼續留在這個行業裡的？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那，那是……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제프티 바이오테크 사와 연루된 스캔들에서 당신의 혐의를 부정해 준 사람은 누구였을까요?","JPN":"ジェフティ・バイオテック社に関与したスキャンダルで、あなたの疑いを晴らしてあげた人は誰ですか？","ENG":"Who was the one who denied your allegations in the scandal involving Jehuty Biotech?","TWN":"傑夫堤生物科技公司的醜聞中，又是誰為你洗清了嫌疑？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"죄, 죄송해요. 스완님.","JPN":"も、申し訳ありません。スワンさん。","ENG":"I-I'll apologize, Miss Swan.","TWN":"對，對不起。史旺。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 죄송할 건 없어요. 당신을 제 매니저로 캐스팅한 이유는 하나거든요.","JPN":"いいえ、謝る必要はありません。あなたを私のマネージャーとしてキャスティングした理由はただ一つ。","ENG":"No. There is nothing to be sorry about. There's only one reason I hired you as my manager.","TWN":"不，不用道歉。我選擇你做我的經紀人只有一個原因。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의외로 자기 분수를 잘 아는 사람이니까요.","JPN":"意外と身の程をわきまえているからです。","ENG":"You're someone who knows your place.","TWN":"你是個意外清楚自己分寸的人。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가서, 감독에게 전하세요.","JPN":"監督に伝えてください。","ENG":"Go tell this to the director.","TWN":"去告訴導演。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"수정한 각본에 맞춰서, 로케이션을 변경하겠다고.","JPN":"修正した脚本に合わせて、ロケ地を変更すると。","ENG":"We are going to change locations according to the revised script.","TWN":"根據修改後的劇本，要更換拍攝地點了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"촬영지를 변경이요……?","JPN":"ロケ地を変更……？","ENG":"Change the location...?","TWN":"更換拍攝地點……？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 그라운드 원은 어쩌고요……?","JPN":"じゃあ、グラウンド・ワンは……？","ENG":"Then, what about Ground One...?","TWN":"那麼，G1怎麼辦……？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳에서 볼 일은 이미 끝났답니다.","JPN":"ここはもう用済みです。","ENG":"My business here is done.","TWN":"在這裡要辦的事已經結束了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다음 로케이션은…….","JPN":"次のロケ地は……","ENG":"The next location is...","TWN":"下一個地點是……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, 챔버로 하죠.","JPN":"そうですね、チェンバーにしましょう。","ENG":"Yes. Chamber will do.","TWN":"好吧，就去強巴吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};